+/* Главный контейнер экрана — теперь это просто прозрачный флекс-ряд */
+.services__board {
+  align-self: center;
+  box-sizing: border-box;
+  /* border: 4px solid rgba(241, 125, 17, 1); <- УДАЛЯЕМ эту оранжевую рамку отсюда */
+  background-color: transparent; /* Убираем общий фон, он будет у карточек */
+  display: flex;
+  flex-direction: row;
+  margin-top: 72px;
+  gap: 30px; /* Зазор между левой колонкой и правой карточкой (подберите точный по макету) */
+}
+
+/* Левая часть: задаем идеальный шаг в 15px между всеми вкладками */
+.services__tabs {
+  display: flex;
+  flex-direction: column;
+  width: 386px; 
+  flex-shrink: 0; 
+  gap: 15px; /* Единый макетный шаг для всех 4-х плашек */
+}
+
+/* Базовый стиль одной карточки-вкладки */
+.tabCard {
+  width: 386px;  
+  height: 177px; 
+  box-sizing: border-box;
+  border: 4px solid rgba(241, 125, 17, 1); /* Переносим оранжевую рамку на сами вкладки */
+  background-color: #171d11; /* Каждая плашка имеет свой темный фон */
+  
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  cursor: pointer;
+  
+  font-family: 'Montserrat', sans-serif;
+  font-size: 18px;
+  font-weight: 500;
+  color: #ffffff;
+  text-align: center;
+}

